installation.script:
#!/bin/bash
set -e

mkdir -p /mnt/server/.ringracers
mkdir -p /mnt/server/addons/chars
mkdir -p /mnt/server/addons/tracks
mkdir -p /mnt/server/addons/loadfirst
mkdir -p /mnt/server/addons/loadlast

if [ ! -f /mnt/server/ringserv.cfg ]; then
    cat > /mnt/server/ringserv.cfg << 'EOF'
// Ring Racers Server Configuration
// Loaded automatically on server start.

// Register on the public master server list (0 = private, 1 = public)
masterserver 0

// Set your contact address so Master Server staff can reach you if needed
// server_contact "your@email.com"

// http_source is managed automatically by the startup script.
// Set the HTTP_SOURCE variable in the Pterodactyl startup tab.
EOF
fi

echo "Installation complete!"
